# solution.py
"""Team Collaboration Manager.

A thread-safe, in-memory collaboration backend that manages users, projects,
tasks, messages, performance metrics and reports.

The public surface (classes, enums and exceptions) is defined to satisfy the
accompanying ``test_solution.py`` suite. All read accessors return deep copies
so that callers can never mutate internal state through a returned object, and
every mutating operation is guarded by a single shared re-entrant lock so the
manager behaves correctly under concurrent access.
"""

import copy
import csv
import io
import threading
from datetime import datetime
from enum import Enum


# ---------------------------------------------------------------------------
# Enumerations
# ---------------------------------------------------------------------------
class UserRole(Enum):
    """Roles a user can hold within the system."""

    ADMIN = "admin"
    MEMBER = "member"
    VIEWER = "viewer"
    GUEST = "guest"


class TaskStatus(Enum):
    """Lifecycle states for a task."""

    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class ReportFormat(Enum):
    """Supported export formats for reports."""

    CSV = "csv"
    PDF = "pdf"


class ReportType(Enum):
    """Kinds of report the manager can produce."""

    PROJECT_PROGRESS = "project_progress"
    TEAM_PERFORMANCE = "team_performance"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Exception hierarchy
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    """Base class for all errors raised by the manager."""


class ValidationError(TeamCollaborationError):
    """Raised when input fails validation."""


class NotFoundError(TeamCollaborationError):
    """Raised when a referenced entity does not exist."""


class AuthorizationError(TeamCollaborationError):
    """Raised when an actor is not permitted to perform an operation."""


class DuplicateError(TeamCollaborationError):
    """Raised when a uniqueness constraint would be violated."""


class ConflictError(TeamCollaborationError):
    """Raised when an operation conflicts with existing state."""


# ---------------------------------------------------------------------------
# Domain models
# ---------------------------------------------------------------------------
class Attachment(object):
    """A file attached to a message."""

    __slots__ = ("filename", "size", "uploaded_by", "uploaded_at", "data")

    def __init__(self, filename, size, uploaded_by, uploaded_at, data=None):
        self.filename = filename
        self.size = size
        self.uploaded_by = uploaded_by
        self.uploaded_at = uploaded_at
        self.data = data

    def __repr__(self):
        return "Attachment(filename={0!r}, size={1})".format(
            self.filename, self.size
        )


class User(object):
    """A registered user."""

    __slots__ = ("id", "username", "email", "role", "created_at")

    def __init__(self, id, username, email, role, created_at):
        self.id = id
        self.username = username
        self.email = email
        self.role = role
        self.created_at = created_at

    def __repr__(self):
        return "User(id={0}, username={1!r})".format(self.id, self.username)


class Project(object):
    """A project owned by a user."""

    __slots__ = (
        "id",
        "name",
        "description",
        "start_date",
        "end_date",
        "owner_id",
        "created_at",
    )

    def __init__(
        self, id, name, description, start_date, end_date, owner_id, created_at
    ):
        self.id = id
        self.name = name
        self.description = description
        self.start_date = start_date
        self.end_date = end_date
        self.owner_id = owner_id
        self.created_at = created_at

    def __repr__(self):
        return "Project(id={0}, name={1!r})".format(self.id, self.name)


class Task(object):
    """A unit of work belonging to a project."""

    __slots__ = (
        "id",
        "project_id",
        "title",
        "description",
        "status",
        "assignee_id",
        "deadline",
        "created_at",
        "started_at",
        "completed_at",
    )

    def __init__(
        self,
        id,
        project_id,
        title,
        description="",
        status=TaskStatus.NOT_STARTED,
        assignee_id=None,
        deadline=None,
        created_at=None,
        started_at=None,
        completed_at=None,
    ):
        self.id = id
        self.project_id = project_id
        self.title = title
        self.description = description
        self.status = status
        self.assignee_id = assignee_id
        self.deadline = deadline
        self.created_at = created_at
        self.started_at = started_at
        self.completed_at = completed_at

    def __repr__(self):
        return "Task(id={0}, title={1!r}, status={2})".format(
            self.id, self.title, self.status
        )


class Message(object):
    """A message posted against a project or a task."""

    __slots__ = (
        "id",
        "author_id",
        "body",
        "project_id",
        "task_id",
        "parent_id",
        "attachments",
        "created_at",
        "edited_at",
    )

    def __init__(
        self,
        id,
        author_id,
        body,
        project_id=None,
        task_id=None,
        parent_id=None,
        attachments=None,
        created_at=None,
        edited_at=None,
    ):
        self.id = id
        self.author_id = author_id
        self.body = body
        self.project_id = project_id
        self.task_id = task_id
        self.parent_id = parent_id
        self.attachments = attachments if attachments is not None else []
        self.created_at = created_at
        self.edited_at = edited_at

    def __repr__(self):
        return "Message(id={0}, author_id={1})".format(self.id, self.author_id)


class Rating(object):
    """A peer rating given to a user."""

    __slots__ = (
        "id",
        "rater_id",
        "ratee_id",
        "score",
        "feedback",
        "task_id",
        "created_at",
    )

    def __init__(
        self, id, rater_id, ratee_id, score, feedback, task_id, created_at
    ):
        self.id = id
        self.rater_id = rater_id
        self.ratee_id = ratee_id
        self.score = score
        self.feedback = feedback
        self.task_id = task_id
        self.created_at = created_at

    def __repr__(self):
        return "Rating(id={0}, ratee_id={1}, score={2})".format(
            self.id, self.ratee_id, self.score
        )


# ---------------------------------------------------------------------------
# Internal repositories (share a single lock with the manager)
# ---------------------------------------------------------------------------
class _UserRepo(object):
    def __init__(self, lock):
        self._lock = lock
        self.by_id = {}
        self.by_username = {}
        self.by_email = {}


class _ProjectRepo(object):
    def __init__(self, lock):
        self._lock = lock
        self.by_id = {}


class _TaskRepo(object):
    def __init__(self, lock):
        self._lock = lock
        self.by_id = {}
        self.by_project = {}
        self.by_assignee = {}


class _MessageRepo(object):
    def __init__(self, lock):
        self._lock = lock
        self.by_id = {}
        self.by_project = {}
        self.by_task = {}


class _PerformanceRepo(object):
    def __init__(self, lock):
        self._lock = lock
        self.ratings = {}
        self.by_ratee = {}


class _ReportRepo(object):
    def __init__(self, lock):
        self._lock = lock


# ---------------------------------------------------------------------------
# Manager
# ---------------------------------------------------------------------------
class TeamCollaborationManager(object):
    """Coordinates users, projects, tasks, messages, ratings and reports."""

    def __init__(self, now=None):
        self._lock = threading.RLock()
        self._now = now if now is not None else datetime.now
        self._id_counter = 0

        self.users = _UserRepo(self._lock)
        self.projects = _ProjectRepo(self._lock)
        self.tasks = _TaskRepo(self._lock)
        self.messages = _MessageRepo(self._lock)
        self.performance = _PerformanceRepo(self._lock)
        self.reports = _ReportRepo(self._lock)

    # -- internal helpers ---------------------------------------------------
    def _next_id(self):
        self._id_counter += 1
        return self._id_counter

    @staticmethod
    def _copy(obj):
        return copy.deepcopy(obj)

    def _require_user(self, user_id):
        user = self.users.by_id.get(user_id)
        if user is None:
            raise NotFoundError("User {0} not found".format(user_id))
        return user

    def _require_project(self, project_id):
        project = self.projects.by_id.get(project_id)
        if project is None:
            raise NotFoundError("Project {0} not found".format(project_id))
        return project

    def _require_task(self, task_id):
        task = self.tasks.by_id.get(task_id)
        if task is None:
            raise NotFoundError("Task {0} not found".format(task_id))
        return task

    def _require_message(self, message_id):
        message = self.messages.by_id.get(message_id)
        if message is None:
            raise NotFoundError("Message {0} not found".format(message_id))
        return message

    @staticmethod
    def _validate_email(email):
        if not isinstance(email, str):
            raise ValidationError("email must be a string")
        cleaned = email.strip()
        if not cleaned or "@" not in cleaned:
            raise ValidationError("invalid email address")
        return cleaned

    @staticmethod
    def _validate_non_empty(value, label):
        if not isinstance(value, str):
            raise ValidationError("{0} must be a string".format(label))
        cleaned = value.strip()
        if not cleaned:
            raise ValidationError("{0} must not be empty".format(label))
        return cleaned

    def _tasks_for_assignee(self, user_id):
        return [
            self.tasks.by_id[tid]
            for tid in self.tasks.by_assignee.get(user_id, set())
        ]

    def _tasks_for_project(self, project_id):
        return [
            self.tasks.by_id[tid]
            for tid in self.tasks.by_project.get(project_id, set())
        ]

    @staticmethod
    def _completion_time(task):
        if (
            task.status == TaskStatus.COMPLETED
            and task.started_at is not None
            and task.completed_at is not None
        ):
            return (task.completed_at - task.started_at).total_seconds()
        return None

    def _average_completion_time(self, tasks):
        times = [
            self._completion_time(t)
            for t in tasks
            if self._completion_time(t) is not None
        ]
        if not times:
            return None
        return sum(times) / len(times)

    def _rating_stats(self, user_id):
        rids = self.performance.by_ratee.get(user_id, [])
        scores = [self.performance.ratings[rid].score for rid in rids]
        count = len(scores)
        average = (sum(scores) / count) if count else 0.0
        return count, average

    # -- user management ----------------------------------------------------
    def register_user(self, username, email, role=UserRole.MEMBER):
        with self._lock:
            clean_username = self._validate_non_empty(username, "username")
            clean_email = self._validate_email(email)
            if not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")
            if clean_username in self.users.by_username:
                raise DuplicateError("username already in use")
            if clean_email in self.users.by_email:
                raise DuplicateError("email already in use")

            user = User(
                id=self._next_id(),
                username=clean_username,
                email=clean_email,
                role=role,
                created_at=self._now(),
            )
            self.users.by_id[user.id] = user
            self.users.by_username[clean_username] = user.id
            self.users.by_email[clean_email] = user.id
            return self._copy(user)

    def get_user(self, user_id):
        with self._lock:
            return self._copy(self._require_user(user_id))

    def list_users(self):
        with self._lock:
            return [
                self._copy(self.users.by_id[uid])
                for uid in sorted(self.users.by_id)
            ]

    def update_user(self, user_id, username=None, email=None, role=None):
        with self._lock:
            user = self._require_user(user_id)

            new_username = user.username
            new_email = user.email
            new_role = user.role

            if username is not None:
                new_username = self._validate_non_empty(username, "username")
                existing = self.users.by_username.get(new_username)
                if existing is not None and existing != user_id:
                    raise DuplicateError("username already in use")

            if email is not None:
                new_email = self._validate_email(email)
                existing = self.users.by_email.get(new_email)
                if existing is not None and existing != user_id:
                    raise DuplicateError("email already in use")

            if role is not None:
                if not isinstance(role, UserRole):
                    raise ValidationError("role must be a UserRole")
                new_role = role

            if new_username != user.username:
                del self.users.by_username[user.username]
                self.users.by_username[new_username] = user_id
                user.username = new_username

            if new_email != user.email:
                del self.users.by_email[user.email]
                self.users.by_email[new_email] = user_id
                user.email = new_email

            user.role = new_role
            return self._copy(user)

    def delete_user(self, user_id):
        with self._lock:
            user = self._require_user(user_id)

            for project in self.projects.by_id.values():
                if project.owner_id == user_id:
                    raise ConflictError("user owns one or more projects")

            for task in self._tasks_for_assignee(user_id):
                if task.status != TaskStatus.COMPLETED:
                    raise ConflictError("user has open assigned tasks")

            self.tasks.by_assignee.pop(user_id, None)
            del self.users.by_username[user.username]
            del self.users.by_email[user.email]
            del self.users.by_id[user_id]

    # -- project management -------------------------------------------------
    def create_project(
        self, name, start_date, end_date, owner_id, description=""
    ):
        with self._lock:
            clean_name = self._validate_non_empty(name, "name")
            if end_date < start_date:
                raise ValidationError("end_date must not precede start_date")
            self._require_user(owner_id)

            project = Project(
                id=self._next_id(),
                name=clean_name,
                description=description,
                start_date=start_date,
                end_date=end_date,
                owner_id=owner_id,
                created_at=self._now(),
            )
            self.projects.by_id[project.id] = project
            return self._copy(project)

    def get_project(self, project_id):
        with self._lock:
            return self._copy(self._require_project(project_id))

    def list_projects(self):
        with self._lock:
            return [
                self._copy(self.projects.by_id[pid])
                for pid in sorted(self.projects.by_id)
            ]

    def update_project(
        self,
        project_id,
        name=None,
        start_date=None,
        end_date=None,
        description=None,
    ):
        with self._lock:
            project = self._require_project(project_id)

            new_name = project.name
            new_start = project.start_date
            new_end = project.end_date
            new_description = project.description

            if name is not None:
                new_name = self._validate_non_empty(name, "name")
            if start_date is not None:
                new_start = start_date
            if end_date is not None:
                new_end = end_date
            if description is not None:
                new_description = description

            if new_end < new_start:
                raise ValidationError("end_date must not precede start_date")

            project.name = new_name
            project.start_date = new_start
            project.end_date = new_end
            project.description = new_description
            return self._copy(project)

    def delete_project(self, project_id):
        with self._lock:
            self._require_project(project_id)

            for tid in list(self.tasks.by_project.get(project_id, set())):
                task = self.tasks.by_id.pop(tid, None)
                if task is not None and task.assignee_id is not None:
                    assigned = self.tasks.by_assignee.get(task.assignee_id)
                    if assigned is not None:
                        assigned.discard(tid)
                for mid in list(self.messages.by_task.get(tid, set())):
                    self.messages.by_id.pop(mid, None)
                self.messages.by_task.pop(tid, None)
            self.tasks.by_project.pop(project_id, None)

            for mid in list(self.messages.by_project.get(project_id, set())):
                self.messages.by_id.pop(mid, None)
            self.messages.by_project.pop(project_id, None)

            del self.projects.by_id[project_id]

    # -- task management ----------------------------------------------------
    def create_task(self, project_id, title, assignee_id=None, deadline=None):
        with self._lock:
            project = self._require_project(project_id)
            clean_title = self._validate_non_empty(title, "title")
            if assignee_id is not None:
                self._require_user(assignee_id)
            if deadline is not None and deadline < project.start_date:
                raise ValidationError("deadline must not precede project start")

            task = Task(
                id=self._next_id(),
                project_id=project_id,
                title=clean_title,
                status=TaskStatus.NOT_STARTED,
                assignee_id=assignee_id,
                deadline=deadline,
                created_at=self._now(),
            )
            self.tasks.by_id[task.id] = task
            self.tasks.by_project.setdefault(project_id, set()).add(task.id)
            if assignee_id is not None:
                self.tasks.by_assignee.setdefault(assignee_id, set()).add(
                    task.id
                )
            return self._copy(task)

    def get_task(self, task_id):
        with self._lock:
            return self._copy(self._require_task(task_id))

    def list_tasks_by_project(self, project_id):
        with self._lock:
            self._require_project(project_id)
            return [
                self._copy(self.tasks.by_id[tid])
                for tid in sorted(self.tasks.by_project.get(project_id, set()))
            ]

    def list_tasks_by_assignee(self, user_id):
        with self._lock:
            self._require_user(user_id)
            return [
                self._copy(self.tasks.by_id[tid])
                for tid in sorted(self.tasks.by_assignee.get(user_id, set()))
            ]

    def assign_task(self, task_id, assignee_id):
        with self._lock:
            task = self._require_task(task_id)
            self._require_user(assignee_id)
            self._set_assignee(task, assignee_id)
            return self._copy(task)

    def reassign_task(self, task_id, new_assignee_id):
        with self._lock:
            task = self._require_task(task_id)
            self._require_user(new_assignee_id)
            self._set_assignee(task, new_assignee_id)
            return self._copy(task)

    def unassign_task(self, task_id):
        with self._lock:
            task = self._require_task(task_id)
            self._set_assignee(task, None)
            return self._copy(task)

    def _set_assignee(self, task, assignee_id):
        old = task.assignee_id
        if old == assignee_id:
            return
        if old is not None:
            assigned = self.tasks.by_assignee.get(old)
            if assigned is not None:
                assigned.discard(task.id)
        task.assignee_id = assignee_id
        if assignee_id is not None:
            self.tasks.by_assignee.setdefault(assignee_id, set()).add(task.id)

    def set_deadline(self, task_id, deadline):
        with self._lock:
            task = self._require_task(task_id)
            if deadline is not None:
                project = self._require_project(task.project_id)
                if deadline < project.start_date:
                    raise ValidationError(
                        "deadline must not precede project start"
                    )
            task.deadline = deadline
            return self._copy(task)

    def update_status(self, task_id, status):
        with self._lock:
            task = self._require_task(task_id)
            if not isinstance(status, TaskStatus):
                raise ValidationError("status must be a TaskStatus")
            now = self._now()
            if status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now
            elif status == TaskStatus.NOT_STARTED:
                task.started_at = None
                task.completed_at = None
            task.status = status
            return self._copy(task)

    # -- messaging ----------------------------------------------------------
    def post_message(
        self,
        author_id,
        body,
        project_id=None,
        task_id=None,
        attachments=None,
        parent_id=None,
    ):
        with self._lock:
            self._require_user(author_id)

            if (project_id is None) == (task_id is None):
                raise ValidationError(
                    "exactly one of project_id or task_id is required"
                )
            if project_id is not None:
                self._require_project(project_id)
            if task_id is not None:
                self._require_task(task_id)

            body_text = body if body is not None else ""
            raw_attachments = attachments if attachments is not None else []
            if not body_text.strip() and not raw_attachments:
                raise ValidationError("message body or attachment required")

            if parent_id is not None:
                self._require_message(parent_id)

            now = self._now()
            attachment_objs = [
                Attachment(
                    filename=filename,
                    size=len(data),
                    uploaded_by=author_id,
                    uploaded_at=now,
                    data=data,
                )
                for filename, data in raw_attachments
            ]

            message = Message(
                id=self._next_id(),
                author_id=author_id,
                body=body_text,
                project_id=project_id,
                task_id=task_id,
                parent_id=parent_id,
                attachments=attachment_objs,
                created_at=now,
                edited_at=None,
            )
            self.messages.by_id[message.id] = message
            if project_id is not None:
                self.messages.by_project.setdefault(project_id, set()).add(
                    message.id
                )
            if task_id is not None:
                self.messages.by_task.setdefault(task_id, set()).add(message.id)
            return self._copy(message)

    def edit_message(self, message_id, editor_id, new_body):
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != editor_id:
                raise AuthorizationError("only the author may edit a message")
            body_text = new_body if new_body is not None else ""
            if not body_text.strip() and not message.attachments:
                raise ValidationError("message body must not be empty")
            message.body = body_text
            message.edited_at = self._now()
            return self._copy(message)

    def add_attachment(self, message_id, uploader_id, filename, data):
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != uploader_id:
                raise AuthorizationError(
                    "only the author may attach to a message"
                )
            self._validate_non_empty(filename, "filename")
            attachment = Attachment(
                filename=filename,
                size=len(data),
                uploaded_by=uploader_id,
                uploaded_at=self._now(),
                data=data,
            )
            message.attachments.append(attachment)
            return self._copy(message)

    def list_messages_by_project(self, project_id):
        with self._lock:
            self._require_project(project_id)
            return [
                self._copy(self.messages.by_id[mid])
                for mid in sorted(
                    self.messages.by_project.get(project_id, set())
                )
            ]

    def list_messages_by_task(self, task_id):
        with self._lock:
            self._require_task(task_id)
            return [
                self._copy(self.messages.by_id[mid])
                for mid in sorted(self.messages.by_task.get(task_id, set()))
            ]

    def delete_message(self, message_id, requester_id):
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != requester_id:
                raise AuthorizationError(
                    "only the author may delete a message"
                )
            if message.project_id is not None:
                stored = self.messages.by_project.get(message.project_id)
                if stored is not None:
                    stored.discard(message_id)
            if message.task_id is not None:
                stored = self.messages.by_task.get(message.task_id)
                if stored is not None:
                    stored.discard(message_id)
            del self.messages.by_id[message_id]

    # -- performance dashboard ---------------------------------------------
    def get_completion_rate(self, user_id):
        with self._lock:
            self._require_user(user_id)
            tasks = self._tasks_for_assignee(user_id)
            if not tasks:
                return 0.0
            completed = sum(
                1 for t in tasks if t.status == TaskStatus.COMPLETED
            )
            return completed / len(tasks)

    def get_average_completion_time(self, user_id):
        with self._lock:
            self._require_user(user_id)
            return self._average_completion_time(
                self._tasks_for_assignee(user_id)
            )

    def submit_rating(
        self, rater_id, ratee_id, score, feedback=None, task_id=None
    ):
        with self._lock:
            if not isinstance(score, int) or isinstance(score, bool):
                raise ValidationError("score must be an integer")
            if score < 1 or score > 5:
                raise ValidationError("score must be between 1 and 5")
            self._require_user(rater_id)
            self._require_user(ratee_id)
            if rater_id == ratee_id:
                raise ConflictError("users cannot rate themselves")
            if task_id is not None:
                self._require_task(task_id)

            rating = Rating(
                id=self._next_id(),
                rater_id=rater_id,
                ratee_id=ratee_id,
                score=score,
                feedback=feedback,
                task_id=task_id,
                created_at=self._now(),
            )
            self.performance.ratings[rating.id] = rating
            self.performance.by_ratee.setdefault(ratee_id, []).append(rating.id)
            return self._copy(rating)

    def get_ratings_summary(self, user_id):
        with self._lock:
            self._require_user(user_id)
            rids = self.performance.by_ratee.get(user_id, [])
            ratings = [
                self._copy(self.performance.ratings[rid]) for rid in rids
            ]
            count = len(ratings)
            average = (
                sum(r.score for r in ratings) / count if count else 0.0
            )
            return {
                "count": count,
                "average": average,
                "ratings": ratings,
            }

    def get_user_dashboard(self, user_id):
        with self._lock:
            self._require_user(user_id)
            tasks = self._tasks_for_assignee(user_id)
            total = len(tasks)
            completed = sum(
                1 for t in tasks if t.status == TaskStatus.COMPLETED
            )
            in_progress = sum(
                1 for t in tasks if t.status == TaskStatus.IN_PROGRESS
            )
            not_started = sum(
                1 for t in tasks if t.status == TaskStatus.NOT_STARTED
            )
            completion_rate = (completed / total) if total else 0.0
            avg_time = self._average_completion_time(tasks)
            rating_count, rating_average = self._rating_stats(user_id)
            return {
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": completion_rate,
                "average_completion_time": avg_time,
                "rating_count": rating_count,
                "rating_average": rating_average,
            }

    # -- reports ------------------------------------------------------------
    def project_progress_report(self, project_id):
        with self._lock:
            self._require_project(project_id)
            tasks = self._tasks_for_project(project_id)
            now = self._now()

            status_counts = {status.value: 0 for status in TaskStatus}
            overdue = 0
            per_assignee = {}
            for task in tasks:
                status_counts[task.status.value] += 1
                if (
                    task.deadline is not None
                    and task.deadline < now
                    and task.status != TaskStatus.COMPLETED
                ):
                    overdue += 1
                if task.assignee_id is not None:
                    bucket = per_assignee.setdefault(
                        task.assignee_id,
                        {"total_tasks": 0, "completed_tasks": 0},
                    )
                    bucket["total_tasks"] += 1
                    if task.status == TaskStatus.COMPLETED:
                        bucket["completed_tasks"] += 1

            for bucket in per_assignee.values():
                tot = bucket["total_tasks"]
                bucket["completion_rate"] = (
                    bucket["completed_tasks"] / tot if tot else 0.0
                )

            total = len(tasks)
            completed = status_counts[TaskStatus.COMPLETED.value]
            completion_rate = (completed / total) if total else 0.0
            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "total_tasks": total,
                "status_counts": status_counts,
                "completion_rate": completion_rate,
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
            }

    def team_performance_report(self, project_id=None):
        with self._lock:
            if project_id is not None:
                self._require_project(project_id)
                scope_tasks = self._tasks_for_project(project_id)
            else:
                scope_tasks = list(self.tasks.by_id.values())

            by_user = {}
            for task in scope_tasks:
                if task.assignee_id is not None:
                    by_user.setdefault(task.assignee_id, []).append(task)

            rows = []
            for uid in sorted(by_user):
                tasks = by_user[uid]
                total = len(tasks)
                completed = sum(
                    1 for t in tasks if t.status == TaskStatus.COMPLETED
                )
                completion_rate = (completed / total) if total else 0.0
                avg_time = self._average_completion_time(tasks)
                rating_count, rating_average = self._rating_stats(uid)
                rows.append(
                    {
                        "user_id": uid,
                        "total_tasks": total,
                        "completed_tasks": completed,
                        "completion_rate": completion_rate,
                        "average_completion_time": avg_time,
                        "rating_count": rating_count,
                        "rating_average": rating_average,
                    }
                )

            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "project_id": project_id,
                "rows": rows,
            }

    def individual_performance_report(self, user_id):
        with self._lock:
            self._require_user(user_id)
            tasks = sorted(
                self._tasks_for_assignee(user_id), key=lambda t: t.id
            )
            total = len(tasks)
            completed = sum(
                1 for t in tasks if t.status == TaskStatus.COMPLETED
            )
            completion_rate = (completed / total) if total else 0.0
            avg_time = self._average_completion_time(tasks)
            rating_count, rating_average = self._rating_stats(user_id)

            task_rows = [
                {
                    "task_id": t.id,
                    "title": t.title,
                    "status": t.status.value,
                    "project_id": t.project_id,
                    "deadline": t.deadline,
                    "started_at": t.started_at,
                    "completed_at": t.completed_at,
                }
                for t in tasks
            ]

            return {
                "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "completion_rate": completion_rate,
                "average_completion_time": avg_time,
                "rating_count": rating_count,
                "rating_average": rating_average,
                "tasks": task_rows,
            }

    def export_report(self, report, report_format):
        if not isinstance(report_format, ReportFormat):
            raise ValidationError("report_format must be a ReportFormat")
        if not isinstance(report, dict):
            raise ValidationError("report must be a dict")
        if report_format == ReportFormat.CSV:
            return self._export_csv(report)
        if report_format == ReportFormat.PDF:
            return self._export_pdf(report)
        raise ValidationError("unsupported report format")

    # -- export helpers -----------------------------------------------------
    @staticmethod
    def _export_csv(report):
        output = io.StringIO()
        writer = csv.writer(output)

        rows = report.get("rows")
        if isinstance(rows, list):
            if rows:
                header = list(rows[0].keys())
            else:
                header = ["user_id"]
            writer.writerow(header)
            for row in rows:
                writer.writerow([row.get(key, "") for key in header])
        else:
            scalars = []
            for key, value in report.items():
                if isinstance(value, dict):
                    for sub_key, sub_value in value.items():
                        scalars.append(
                            ("{0}.{1}".format(key, sub_key), sub_value)
                        )
                elif not isinstance(value, list):
                    scalars.append((key, value))
            if not scalars:
                scalars.append(("report", ""))
            writer.writerow([key for key, _ in scalars])
            writer.writerow([value for _, value in scalars])

        return output.getvalue()

    @staticmethod
    def _export_pdf(report):
        title = str(report.get("report_type", "report"))
        lines = []
        for key, value in report.items():
            if isinstance(value, (list, dict)):
                lines.append("{0}: {1}".format(key, len(value)))
            else:
                lines.append("{0}: {1}".format(key, value))

        text_lines = [title] + lines
        content_ops = ["BT", "/F1 12 Tf", "50 760 Td", "14 TL"]
        for index, line in enumerate(text_lines):
            escaped = (
                line.replace("\\", "\\\\")
                .replace("(", "\\(")
                .replace(")", "\\)")
            )
            if index == 0:
                content_ops.append("({0}) Tj".format(escaped))
            else:
                content_ops.append("T* ({0}) Tj".format(escaped))
        content_ops.append("ET")
        content = "\n".join(content_ops).encode("latin-1", "replace")

        objects = [
            b"<< /Type /Catalog /Pages 2 0 R >>",
            b"<< /Type /Pages /Kids [3 0 R] /Count 1 >>",
            (
                b"<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
                b"/Contents 4 0 R /Resources << /Font << /F1 5 0 R >> >> >>"
            ),
            b"<< /Length "
            + str(len(content)).encode("latin-1")
            + b" >>\nstream\n"
            + content
            + b"\nendstream",
            b"<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>",
        ]

        pdf = bytearray(b"%PDF-1.4\n")
        offsets = []
        for number, body in enumerate(objects, start=1):
            offsets.append(len(pdf))
            pdf += str(number).encode("latin-1")
            pdf += b" 0 obj\n"
            pdf += body
            pdf += b"\nendobj\n"

        xref_position = len(pdf)
        size = len(objects) + 1
        pdf += b"xref\n"
        pdf += b"0 " + str(size).encode("latin-1") + b"\n"
        pdf += b"0000000000 65535 f \n"
        for offset in offsets:
            pdf += "{0:010d} 00000 n \n".format(offset).encode("latin-1")
        pdf += b"trailer\n<< /Size "
        pdf += str(size).encode("latin-1")
        pdf += b" /Root 1 0 R >>\n"
        pdf += b"startxref\n"
        pdf += str(xref_position).encode("latin-1")
        pdf += b"\n%%EOF"
        return bytes(pdf)
